 13→function isJsonString(text: string): boolean {
 14→  const trimmed = text.trim();
 15→  if (
 16→    (trimmed.startsWith("{") && trimmed.endsWith("}")) ||
 17→    (trimmed.startsWith("[") && trimmed.endsWith("]"))
 18→  ) {
 19→    try {
 20→      JSON.parse(trimmed);
 21→      return true;
 22→    } catch {
 23→      return false;
 24→    }
 25→  }
 26→  return false;
 27→}
 28→
 29→function MarkdownContent({ content }: { content: string }) {
 30→  return (
 31→    <div className="prose-transcript">
 32→      <ReactMarkdown remarkPlugins={[remarkGfm]}>{content}</ReactMarkdown>
 33→    </div>
 34→  );
 35→}
 36→
 37→function MessageContent({ content, toolInput }: { content: string; toolInput: string | null }) {
 38→  if (toolInput) {
 39→    if (isJsonString(toolInput)) {
 40→      return <JsonViewer text={toolInput} />;
 41→    }
 42→    return (
 43→      <pre className="overflow-x-auto whitespace-pre-wrap font-mono text-xs text-fg-subtle">
