  1→import { useEffect, useRef, useCallback } from "react";
  2→import { invoke } from "@tauri-apps/api/core";
  3→
  4→interface GhosttyTerminalProps {
  5→  surfaceId: string | null;
  6→  className?: string;
  7→  dialogOpen?: boolean;
  8→}
  9→
 10→/**
 11→ * Transparent placeholder that positions a native NSView overlay for libghostty.
 12→ *
 13→ * The actual terminal rendering happens in Metal via libghostty — this div
 14→ * just tracks its position/size in the viewport and syncs it to the native layer.
 15→ */
 16→export function GhosttyTerminal({ surfaceId, className, dialogOpen }: GhosttyTerminalProps) {
 17→  const containerRef = useRef<HTMLDivElement>(null);
 18→  const rafRef = useRef<number>(0);
 19→
 20→  // Sync the native overlay position to match this div's position in the viewport
 21→  const syncOverlay = useCallback(() => {
 22→    if (!surfaceId || !containerRef.current) return;
 23→
 24→    const rect = containerRef.current.getBoundingClientRect();
 25→    invoke("ghostty_update_overlay", {
 26→      surfaceId,
 27→      x: rect.x,
 28→      y: rect.y,
 29→      width: rect.width,
 30→      height: rect.height,
 31→    }).catch(console.error);
 32→  }, [surfaceId]);
 33→
 34→  useEffect(() => {
 35→    if (!containerRef.current || !surfaceId) return;
 36→
 37→    // Initial sync
 38→    syncOverlay();
 39→
 40→    // Show the overlay
 41→    invoke("ghostty_show_overlay", { surfaceId, visible: true })
 42→      .then(() => invoke("ghostty_focus_overlay", { surfaceId }))
 43→      .catch(console.error);
 44→
 45→    // Track resize/reposition
 46→    const observer = new ResizeObserver(() => {
 47→      cancelAnimationFrame(rafRef.current);
 48→      rafRef.current = requestAnimationFrame(syncOverlay);
 49→    });
 50→    observer.observe(containerRef.current);
 51→
 52→    // Also sync on scroll (in case the terminal is inside a scrollable container)
 53→    const onScroll = () => {
 54→      cancelAnimationFrame(rafRef.current);
 55→      rafRef.current = requestAnimationFrame(syncOverlay);
 56→    };
 57→    window.addEventListener("scroll", onScroll, true);
 58→
 59→    return () => {
 60→      observer.disconnect();
 61→      window.removeEventListener("scroll", onScroll, true);
 62→      cancelAnimationFrame(rafRef.current);
 63→
 64→      // Hide overlay when component unmounts
 65→      invoke("ghostty_show_overlay", { surfaceId, visible: false }).catch(
 66→        console.error
 67→      );
 68→    };
 69→  }, [surfaceId, syncOverlay]);
 70→
 71→  // Hide overlay when a dialog is open so native NSView doesn't cover it
 72→  useEffect(() => {
 73→    if (!surfaceId) return;
 74→    invoke("ghostty_show_overlay", { surfaceId, visible: !dialogOpen }).catch(
 75→      console.error
 76→    );
 77→  }, [surfaceId, dialogOpen]);
 78→
 79→  // Click to focus the native terminal
 80→  const handleClick = useCallback(() => {
 81→    if (surfaceId) {
 82→      invoke("ghostty_focus_overlay", { surfaceId }).catch(console.error);
 83→    }
 84→  }, [surfaceId]);
 85→
 86→  return (
 87→    <div
 88→      ref={containerRef}
 89→      onClick={handleClick}
 90→      className={`h-full w-full ${className ?? ""}`}
 91→      style={{
 92→        // Transparent so the native Metal view shows through
 93→        background: "transparent",
 94→        // Prevent the webview from capturing events meant for the native overlay
 95→        pointerEvents: surfaceId ? "none" : "auto",
 96→      }}
 97→    >
 98→      {!surfaceId && <div className="h-full w-full" />}
 99→    </div>
100→  );
101→}
