132→/// Destroy a surface and remove its native overlay.
133→#[tauri::command]
134→pub fn ghostty_destroy_surface(
135→    surface_id: String,
136→    state: State<'_, Mutex<super::GhosttyState>>,
137→) -> Result<(), String> {
138→    let mut gs = state.lock().map_err(|_| "State lock error".to_string())?;
139→    if let Some(entry) = gs.surfaces.remove(&surface_id) {
140→        entry.overlay.clear_surface();
141→        drop(entry);
142→    }
143→    // Drop handles cleanup: GhosttySurface::drop frees the libghostty surface,
144→    // GhosttyOverlay::drop removes the NSView from its superview.
145→    Ok(())
146→}
