170→define_class!(
171→    #[unsafe(super(NSView))]
172→    #[thread_kind = MainThreadOnly]
173→    #[ivars = GhosttyHostViewIvars]
174→    #[name = "EntireGhosttyHostView"]
175→    struct GhosttyHostView;
176→
177→    impl GhosttyHostView {
178→        #[unsafe(method(acceptsFirstResponder))]
179→        fn accepts_first_responder(&self) -> bool {
180→            true
181→        }
182→
183→        #[unsafe(method(becomeFirstResponder))]
184→        fn become_first_responder(&self) -> bool {
185→            let result: bool = unsafe { msg_send![super(self), becomeFirstResponder] };
186→            if result {
187→                let surface = self.surface();
188→                if !surface.is_null() {
189→                    unsafe { super::ghostty_surface_set_focus(surface, true) };
190→                }
191→            }
192→            result
193→        }
194→
195→        #[unsafe(method(resignFirstResponder))]
196→        fn resign_first_responder(&self) -> bool {
197→            let result: bool = unsafe { msg_send![super(self), resignFirstResponder] };
198→            if result {
199→                let surface = self.surface();
200→                if !surface.is_null() {
201→                    unsafe { super::ghostty_surface_set_focus(surface, false) };
202→                }
203→            }
204→            result
205→        }
206→
207→        #[unsafe(method(mouseDown:))]
208→        fn mouse_down(&self, event: &NSEvent) {
209→            if let Some(window) = self.window() {
210→                let _: bool = unsafe { msg_send![&*window, makeFirstResponder: self] };
211→            }
212→
213→            let surface = self.surface();
214→            if !surface.is_null() {
215→                let point = self.convertPoint_fromView(event.locationInWindow(), None);
216→                let y = self.bounds().size.height - point.y;
217→                let mods = mods_from_event(event);
218→                unsafe {
219→                    super::ghostty_surface_mouse_pos(surface, point.x, y, mods);
220→                    let _ = super::ghostty_surface_mouse_button(
221→                        surface,
222→                        GhosttyMouseState::Press,
223→                        GhosttyMouseButton::Left,
224→                        mods,
225→                    );
226→                }
227→            } else {
228→                unsafe { msg_send![super(self), mouseDown: event] }
229→            }
230→        }
231→
232→        #[unsafe(method(mouseUp:))]
233→        fn mouse_up(&self, event: &NSEvent) {
234→            let surface = self.surface();
235→            if !surface.is_null() {
236→                let mods = mods_from_event(event);
237→                unsafe {
238→                    let _ = super::ghostty_surface_mouse_button(
239→                        surface,
240→                        GhosttyMouseState::Release,
241→                        GhosttyMouseButton::Left,
242→                        mods,
243→                    );
244→                }
245→            } else {
246→                unsafe { msg_send![super(self), mouseUp: event] }
247→            }
248→        }
249→
250→        #[unsafe(method(mouseDragged:))]
251→        fn mouse_dragged(&self, event: &NSEvent) {
252→            let surface = self.surface();
253→            if !surface.is_null() {
254→                let point = self.convertPoint_fromView(event.locationInWindow(), None);
255→                let y = self.bounds().size.height - point.y;
256→                let mods = mods_from_event(event);
257→                unsafe {
258→                    super::ghostty_surface_mouse_pos(surface, point.x, y, mods);
259→                }
260→            } else {
261→                unsafe { msg_send![super(self), mouseDragged: event] }
262→            }
263→        }
264→
265→        #[unsafe(method(scrollWheel:))]
266→        fn scroll_wheel(&self, event: &NSEvent) {
267→            let surface = self.surface();
268→            if !surface.is_null() {
269→                if let Some(window) = self.window() {
270→                    let _: bool = unsafe { msg_send![&*window, makeFirstResponder: self] };
271→                }
272→
273→                let point = self.convertPoint_fromView(event.locationInWindow(), None);
274→                let y = self.bounds().size.height - point.y;
275→                let mods = mods_from_event(event);
276→                let scroll_mods = GhosttyScrollMods {
277→                    precision: event.hasPreciseScrollingDeltas(),
278→                };
279→
280→                unsafe {
281→                    super::ghostty_surface_set_focus(surface, true);
282→                    super::ghostty_surface_mouse_pos(surface, point.x, y, mods);
283→                    super::ghostty_surface_mouse_scroll(
284→                        surface,
285→                        event.scrollingDeltaX(),
286→                        event.scrollingDeltaY(),
287→                        scroll_mods,
288→                    );
289→                }
290→            } else {
291→                unsafe { msg_send![super(self), scrollWheel: event] }
292→            }
293→        }
294→
295→        #[unsafe(method(keyDown:))]
296→        fn key_down(&self, event: &NSEvent) {
297→            let surface = self.surface();
298→            if !surface.is_null() {
299→                unsafe { super::ghostty_surface_set_focus(surface, true) };
300→                if matches_command_shortcut(event, 'v') && paste_clipboard_text(surface) {
301→                    debug_log("ghostty_host_view: handled command+v via system pasteboard");
302→                    return;
303→                }
304→                if matches_command_shortcut(event, 'c') {
305→                    // Forward Cmd+C to ghostty — it will trigger
306→                    // runtime_write_clipboard if there is a selection.
307→                    let handled = send_key_event(surface, event);
308→                    debug_log(&format!(
309→                        "ghostty_host_view: handled command+c, ghostty_handled={}",
310→                        handled,
311→                    ));
312→                    return;
313→                }
314→                let handled = send_key_event(surface, event);
315→                let text = event
316→                    .characters()
317→                    .map(|chars| chars.to_string())
318→                    .unwrap_or_default();
319→                debug_log(&format!(
320→                    "ghostty_host_view: keyDown keyCode={} handled={} chars={:?}",
321→                    event.keyCode(),
322→                    handled,
323→                    text,
324→                ));
325→                if handled {
326→                    return;
327→                }
328→            }
329→
330→            unsafe { msg_send![super(self), keyDown: event] }
331→        }
332→
333→        #[unsafe(method(copy:))]
334→        fn copy(&self, _sender: Option<&AnyObject>) {
335→            let surface = self.surface();
336→            if !surface.is_null() {
337→                let key = GhosttyInputKey {
338→                    action: GhosttyInputAction::Press,
339→                    mods: GhosttyInputMods::SUPER,
340→                    consumed_mods: GhosttyInputMods::NONE,
341→                    keycode: 8, // macOS keycode for 'c'
342→                    text: ptr::null(),
343→                    unshifted_codepoint: 'c' as u32,
344→                    composing: false,
345→                };
346→                unsafe { super::ghostty_surface_key(surface, key); }
347→            }
348→        }
349→
350→        #[unsafe(method(paste:))]
351→        fn paste(&self, _sender: Option<&AnyObject>) {
352→            let surface = self.surface();
353→            if !surface.is_null() {
354→                unsafe { super::ghostty_surface_set_focus(surface, true) };
355→                let _ = paste_clipboard_text(surface);
356→            }
357→        }
358→
359→        #[unsafe(method(doCommandBySelector:))]
360→        fn do_command_by_selector(&self, _selector: Sel) {
361→            // Prevent NSBeep for commands we intentionally leave to Ghostty.
362→        }
363→    }
364→);
