500→/// Get the raw NSWindow pointer from a Tauri webview window.
501→pub fn get_nswindow(window: &tauri::WebviewWindow) -> Result<*mut c_void, String> {
502→    #[cfg(target_os = "macos")]
503→    {
504→        use raw_window_handle::{HasWindowHandle, RawWindowHandle};
505→
506→        let handle = window
507→            .window_handle()
508→            .map_err(|e| format!("Failed to get window handle: {}", e))?;
509→
510→        match handle.as_raw() {
511→            RawWindowHandle::AppKit(handle) => {
512→                // ns_view is the content view — we need the window.
513→                // Get the window from the view.
514→                let ns_view = handle.ns_view.as_ptr() as *mut c_void;
515→                let ns_window: *mut c_void =
516→                    unsafe { msg_send![ns_view as *mut AnyObject, window] };
517→                Ok(ns_window)
518→            }
519→            _ => Err("Expected AppKit window handle on macOS".into()),
520→        }
521→    }
522→
523→    #[cfg(not(target_os = "macos"))]
524→    {
