  4→import type { CheckpointSummary } from "../../lib/ipc";
  5→
  6→interface CheckpointListProps {
  7→  repoPath: string;
  8→  branch: string;
  9→  onSelectCheckpoint?: (checkpoint: CheckpointSummary) => void;
 10→}
 11→
 12→function formatTokens(usage: CheckpointSummary["token_usage"]): string | null {
 13→  if (!usage) return null;
 14→  const total = usage.input_tokens + usage.output_tokens;
 15→  if (total >= 1000) return `${(total / 1000).toFixed(1)}k tokens`;
 16→  return `${total} tokens`;
 17→}
 18→
 19→function timeAgo(isoDate: string): string {
 20→  const diff = Date.now() - new Date(isoDate).getTime();
 21→  const mins = Math.floor(diff / 60000);
 22→  if (mins < 1) return "just now";
 23→  if (mins < 60) return `${mins}m ago`;
 24→  const hours = Math.floor(mins / 60);
 25→  if (hours < 24) return `${hours}h ago`;
 26→  return `${Math.floor(hours / 24)}d ago`;
 27→}
 28→
 29→export function CheckpointList({ repoPath, branch, onSelectCheckpoint }: CheckpointListProps) {
 30→  const { data: realCheckpoints, isLoading } = useCheckpointsQuery(repoPath, branch);
 31→
 32→  const checkpoints = realCheckpoints ?? [];
 33→
 34→  const [selectedId, setSelectedId] = useState<string | null>(null);
 35→  const [search, setSearch] = useState("");
 36→
 37→  const filtered = search
 38→    ? checkpoints.filter((cp) =>
 39→        cp.commit_message.toLowerCase().includes(search.toLowerCase()) ||
 40→        cp.checkpoint_id.toLowerCase().includes(search.toLowerCase())
 41→      )
 42→    : checkpoints;
 43→
 44→  return (
 45→    <div>
 46→      {/* Search */}
 47→      <div className="p-5 pb-3">
 48→        <div className="relative">
 49→          <Search
 50→            size={14}
 51→            className="absolute left-3 top-1/2 -translate-y-1/2 text-fg-subtle"
 52→          />
 53→          <input
 54→            value={search}
 55→            onChange={(e) => setSearch(e.target.value)}
 56→            placeholder="Search checkpoints... (⌘K)"
 57→            className="w-full rounded-lg border border-border bg-bg-overlay py-2 pl-9 pr-3 text-[13px] text-fg outline-none transition-colors placeholder:text-fg-subtle focus:border-accent"
 58→          />
 59→          {isLoading && (
 60→            <Loader2
 61→              size={14}
 62→              className="absolute right-3 top-1/2 -translate-y-1/2 animate-spin text-fg-subtle"
 63→            />
 64→          )}
 65→        </div>
 66→      </div>
 67→
 68→      {/* List */}
 69→      <div className="px-5 pb-5">
 70→        {filtered.map((cp) => {
 71→          const agent = cp.sessions[0]?.agent ?? null;
 72→          const stepCount = cp.sessions.reduce((sum, s) => sum + s.step_count, 0);
 73→          const tokens = formatTokens(cp.token_usage);
 74→          const isManual = cp.sessions.length === 0;
 75→
 76→          return (
 77→            <button
 78→              key={cp.checkpoint_id}
 79→              onClick={() => {
 80→                setSelectedId(cp.checkpoint_id);
 81→                onSelectCheckpoint?.(cp);
 82→              }}
 83→              className={`mb-2 flex w-full gap-3.5 rounded-[10px] border p-3.5 text-left transition-all ${
 84→                selectedId === cp.checkpoint_id
 85→                  ? "border-accent bg-accent-bg"
 86→                  : "border-border-subtle bg-bg-overlay hover:border-border-hover hover:bg-bg-hover"
 87→              }`}
 88→            >
 89→              {/* Avatar */}
 90→              <div className="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-bg-hover text-sm">
 91→                {agent ? "🤖" : "👤"}
 92→              </div>
 93→
 94→              {/* Content */}
 95→              <div className="min-w-0 flex-1">
 96→                <div className="mb-1 flex items-center gap-2">
 97→                  <span className="truncate text-[13px] font-medium text-fg">
 98→                    {cp.commit_message || cp.checkpoint_id}
 99→                  </span>
100→                  {agent && (
101→                    <span
102→                      className={`shrink-0 rounded px-2 py-0.5 text-[10px] font-medium ${
103→                        agent === "Claude Code"
104→                          ? "bg-accent-bg text-accent-fg"
105→                          : "bg-green-bg text-green"
106→                      }`}
107→                    >
108→                      {agent}
109→                    </span>
110→                  )}
111→                </div>
112→                <div className="flex gap-3 text-[11px] text-fg-muted">
113→                  <span className="font-mono text-fg-subtle">
114→                    {cp.commit_sha ? cp.commit_sha.slice(0, 7) : cp.checkpoint_id.slice(0, 7)}
115→                  </span>
116→                  <span>{cp.files_touched.length} files</span>
117→                  {stepCount > 0 && <span>{stepCount} steps</span>}
118→                  {tokens && <span>{tokens}</span>}
119→                  {isManual && (
120→                    <span className="text-fg-subtle">manual commit</span>
121→                  )}
122→                </div>
123→              </div>
124→
125→              {/* Time */}
126→              {cp.created_at && (
127→                <span className="shrink-0 self-start text-[11px] text-fg-subtle whitespace-nowrap">
128→                  {timeAgo(cp.created_at)}
129→                </span>
130→              )}
131→            </button>
132→          );
133→        })}
134→
135→        {filtered.length === 0 && !isLoading && (
136→          <div className="py-12 text-center text-sm text-fg-subtle">
137→            No checkpoints found
138→          </div>
139→        )}
140→      </div>
141→    </div>
142→  );
143→}
