518→fn decode_clipboard_text(
519→    content: *const GhosttyClipboardContent,
520→    content_len: usize,
521→) -> Option<String> {
522→    if content.is_null() || content_len == 0 {
523→        return None;
524→    }
525→
526→    let chunks = unsafe { std::slice::from_raw_parts(content, content_len) };
527→    let total_len = chunks.iter().map(|chunk| chunk.len).sum();
528→    let mut bytes = Vec::with_capacity(total_len);
529→
530→    for chunk in chunks {
531→        if chunk.data.is_null() || chunk.len == 0 {
532→            continue;
533→        }
534→
535→        let part = unsafe { std::slice::from_raw_parts(chunk.data as *const u8, chunk.len) };
536→        bytes.extend_from_slice(part);
537→    }
538→
539→    String::from_utf8(bytes).ok()
540→}
