14→/** Hook wrapper to fetch a single session file — must be called at top level */
15→function useSessionFile(repoPath: string, sessionId: string) {
16→  const { data, isLoading } = useRawSessionFileQuery(repoPath, sessionId);
17→  return { sessionId, content: data ?? null, loading: isLoading };
18→}
19→
20→export function CheckpointDebugContainer({
21→  repoPath,
22→  checkpoint,
23→}: CheckpointDebugContainerProps) {
24→  const { data: rawMetadata, isLoading: metadataLoading } = useRawCheckpointMetadataQuery(
25→    repoPath,
26→    checkpoint.checkpoint_id
27→  );
28→
29→  // Fetch raw session files for each session in the checkpoint
30→  // We use individual hooks to satisfy React's rules of hooks (stable call count)
31→  // by always calling for up to 4 session slots
32→  const sessionIds = checkpoint.sessions.map((s) => s.session_id);
33→  const s0 = useSessionFile(repoPath, sessionIds[0] ?? "");
34→  const s1 = useSessionFile(repoPath, sessionIds[1] ?? "");
35→  const s2 = useSessionFile(repoPath, sessionIds[2] ?? "");
36→  const s3 = useSessionFile(repoPath, sessionIds[3] ?? "");
37→
38→  const rawSessionFiles = [s0, s1, s2, s3]
39→    .slice(0, sessionIds.length)
40→    .filter((sf) => sf.sessionId !== "");
41→
42→  const { data: checkpointLogs, isLoading: logsLoading } = useCheckpointLogsQuery(
43→    repoPath,
44→    checkpoint.checkpoint_id,
45→    sessionIds
46→  );
47→
48→  return (
49→    <CheckpointDebugView
50→      rawCheckpointMetadata={rawMetadata ?? null}
51→      rawCheckpointMetadataLoading={metadataLoading}
52→      rawSessionFiles={rawSessionFiles}
53→      checkpointLogs={checkpointLogs ?? null}
54→      checkpointLogsLoading={logsLoading}
55→    />
56→  );
57→}
