 7→interface BranchInsightsContainerProps {
 8→  repoPath: string;
 9→  branch: string;
10→}
11→
12→export function BranchInsightsContainer({
13→  repoPath,
14→  branch,
15→}: BranchInsightsContainerProps) {
16→  const { checkpoints, queries } = useBranchTranscriptsQuery(
17→    repoPath,
18→    branch,
19→    true
20→  );
21→
22→  const loadedCount = queries.filter((q) => q.isSuccess).length;
23→  const totalCount = checkpoints.length;
24→  const isLoading = queries.some((q) => q.isLoading);
25→
26→  const insights = useMemo<Insight[]>(() => {
27→    const all: Insight[] = [];
28→    for (let i = 0; i < queries.length; i++) {
29→      const q = queries[i];
30→      if (q.data && checkpoints[i]) {
31→        all.push(...extractInsights(q.data, checkpoints[i]));
32→      }
33→    }
34→    return all;
35→  }, [queries, checkpoints]);
36→
37→  const loadingProgress =
38→    isLoading && totalCount > 0
39→      ? `Loaded insights from ${loadedCount}/${totalCount} checkpoints`
40→      : undefined;
41→
42→  return (
43→    <InsightsView
44→      insights={insights}
45→      isLoading={isLoading && insights.length === 0}
46→      showCheckpointContext={true}
47→      loadingProgress={loadingProgress}
48→    />
49→  );
50→}
