 41→fn mods_from_event(event: &NSEvent) -> GhosttyInputMods {
 42→    let flags = event.modifierFlags();
 43→    let mut mods = GhosttyInputMods::NONE;
 44→
 45→    if flags.contains(NSEventModifierFlags::Shift) {
 46→        mods |= GhosttyInputMods::SHIFT;
 47→    }
 48→    if flags.contains(NSEventModifierFlags::Control) {
 49→        mods |= GhosttyInputMods::CTRL;
 50→    }
 51→    if flags.contains(NSEventModifierFlags::Option) {
 52→        mods |= GhosttyInputMods::ALT;
 53→    }
 54→    if flags.contains(NSEventModifierFlags::Command) {
 55→        mods |= GhosttyInputMods::SUPER;
 56→    }
 57→
 58→    mods
 59→}
 60→
 61→fn consumed_mods_for_event(surface: *mut c_void, event: &NSEvent) -> GhosttyInputMods {
 62→    let translated =
 63→        unsafe { super::ghostty_surface_key_translation_mods(surface, mods_from_event(event)) };
 64→    let mut consumed = GhosttyInputMods::NONE;
 65→
 66→    if translated.contains(GhosttyInputMods::SHIFT) {
 67→        consumed |= GhosttyInputMods::SHIFT;
 68→    }
 69→    if translated.contains(GhosttyInputMods::ALT) {
 70→        consumed |= GhosttyInputMods::ALT;
 71→    }
 72→
 73→    consumed
 74→}
