385→/// Manages a native NSView overlay positioned on top of the Tauri webview.
386→/// Ghostty renders into this view via its own Metal infrastructure.
387→pub struct GhosttyOverlay {
388→    /// The NSView that contains the Metal layer. libghostty renders into this.
389→    view: Retained<GhosttyHostView>,
390→    /// Track visibility so we avoid redundant show/hide calls.
391→    visible: bool,
392→}
393→
394→// SAFETY: NSView operations are dispatched on the main thread via objc2.
395→// The overlay is only mutated through Mutex<GhosttyState>.
396→unsafe impl Send for GhosttyOverlay {}
397→unsafe impl Sync for GhosttyOverlay {}
398→
399→impl GhosttyOverlay {
400→    /// Create a new overlay NSView and add it as a subview of the given window.
401→    ///
402→    /// # Safety
403→    /// Must be called on the main thread. `window` must be a valid NSWindow pointer.
404→    pub unsafe fn new(window: *mut c_void) -> Result<Self, String> {
405→        // We must be on the main thread to create NSView
406→        let mtm = MainThreadMarker::new()
407→            .ok_or_else(|| "Must be called on the main thread".to_string())?;
408→
409→        let window: &NSWindow = unsafe { &*(window as *const NSWindow) };
410→        let content_view = window
411→            .contentView()
412→            .ok_or_else(|| "Window has no contentView".to_string())?;
413→
414→        // Create the overlay NSView
415→        let frame = content_view.frame();
416→        let view = GhosttyHostView::new(mtm, frame);
417→
418→        // Enable layer-backing (required for ghostty's Metal rendering)
419→        // but do NOT pre-create a CAMetalLayer — ghostty sets up its own
420→        // rendering infrastructure on the view internally.
421→        view.setWantsLayer(true);
422→
423→        // Add as subview — on top of the webview content
424→        content_view.addSubview(&view);
425→
426→        // Start hidden until explicitly shown
427→        view.setHidden(true);
428→
429→        Ok(Self {
430→            view,
431→            visible: false,
432→        })
433→    }
434→
435→    /// Returns the raw NSView pointer for passing to libghostty's surface config.
436→    pub fn nsview_ptr(&self) -> *mut c_void {
437→        let view_ref: &NSView = &self.view;
438→        view_ref as *const NSView as *mut c_void
439→    }
440→
441→    pub fn set_surface(&self, surface: *mut c_void) {
442→        self.view.set_surface(surface);
443→    }
444→
445→    pub fn clear_surface(&self) {
446→        self.view.clear_surface();
447→    }
448→
449→    /// Reposition and resize the overlay to match the terminal panel in the webview.
450→    ///
451→    /// Coordinates come from the frontend (top-left origin, CSS pixels).
452→    /// macOS NSView uses bottom-left origin, so we flip Y.
453→    pub fn update_frame(&self, x: f64, y: f64, width: f64, height: f64) {
454→        if let Some(superview) = unsafe { self.view.superview() } {
455→            let parent_height = superview.frame().size.height;
456→            // Convert from top-left (web) to bottom-left (macOS) origin
457→            let flipped_y = parent_height - y - height;
458→
459→            let frame = objc2_foundation::NSRect::new(
460→                objc2_foundation::NSPoint::new(x, flipped_y),
461→                objc2_foundation::NSSize::new(width, height),
462→            );
463→            self.view.setFrame(frame);
464→        }

