    const containerRect = container.getBoundingClientRect();
    const isVisible =
      rect.top >= containerRect.top &&
      rect.bottom <= containerRect.bottom;

    if (!isVisible) {
      const scrollTarget = rect.top - containerRect.top + container.scrollTop - container.clientHeight / 2;
