import { useState, useRef, useEffect, useCallback } from "react";
import { FindBar } from "./FindBar";

interface SearchableContainerProps {
  isSearchOpen: boolean;
  onClose: () => void;
  children: React.ReactNode;
  className?: string;
}

interface MatchRect {
  top: number;
  left: number;
  width: number;
  height: number;
}

interface SearchMatch {
  range: Range;
  rects: MatchRect[];
}

function findTextMatches(container: HTMLElement, query: string): SearchMatch[] {
  if (!query || query.length === 0) return [];

  const lowerQuery = query.toLowerCase();
  const matches: SearchMatch[] = [];
  const walker = document.createTreeWalker(
    container,
    NodeFilter.SHOW_TEXT,
    null
  );

  let node: Text | null;
  while ((node = walker.nextNode() as Text | null)) {
    const text = node.textContent ?? "";
    const lowerText = text.toLowerCase();
    let startIdx = 0;

    while (startIdx < text.length) {
      const matchIdx = lowerText.indexOf(lowerQuery, startIdx);
      if (matchIdx === -1) break;

      const range = document.createRange();
      range.setStart(node, matchIdx);
      range.setEnd(node, matchIdx + query.length);

      const clientRects = range.getClientRects();
      const containerRect = container.getBoundingClientRect();
      const rects: MatchRect[] = [];

      for (let i = 0; i < clientRects.length; i++) {
        const r = clientRects[i];
        rects.push({
          top: r.top - containerRect.top + container.scrollTop,
          left: r.left - containerRect.left + container.scrollLeft,
          width: r.width,
          height: r.height,
        });
      }

      if (rects.length > 0) {
        matches.push({ range, rects });
      }

      startIdx = matchIdx + query.length;
    }
  }

  return matches;
}

export function SearchableContainer({
  isSearchOpen,
  onClose,
  children,
  className,
}: SearchableContainerProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [query, setQuery] = useState("");
  const [matches, setMatches] = useState<SearchMatch[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const debounceRef = useRef<ReturnType<typeof setTimeout>>(0 as unknown as ReturnType<typeof setTimeout>);

  // Recalculate matches when query changes
  useEffect(() => {
    clearTimeout(debounceRef.current);

    if (!query || !containerRef.current) {
      setMatches([]);
      setCurrentIndex(0);
      return;
    }

    debounceRef.current = setTimeout(() => {
      if (!containerRef.current) return;
      const found = findTextMatches(containerRef.current, query);
      setMatches(found);
      setCurrentIndex(found.length > 0 ? 1 : 0);
    }, 150);

    return () => clearTimeout(debounceRef.current);
  }, [query]);

  // Recalculate highlight positions on scroll
  const recalcRects = useCallback(() => {
    if (!containerRef.current || matches.length === 0) return;

    const containerRect = containerRef.current.getBoundingClientRect();
    const scrollTop = containerRef.current.scrollTop;
    const scrollLeft = containerRef.current.scrollLeft;

    setMatches((prev) =>
      prev.map((match) => {
        const clientRects = match.range.getClientRects();
        const rects: MatchRect[] = [];
        for (let i = 0; i < clientRects.length; i++) {
          const r = clientRects[i];
          rects.push({
            top: r.top - containerRect.top + scrollTop,
            left: r.left - containerRect.left + scrollLeft,
            width: r.width,
            height: r.height,
          });
        }
        return { ...match, rects };
      })
    );
  }, [matches.length]);

  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;

    el.addEventListener("scroll", recalcRects, { passive: true });
    return () => el.removeEventListener("scroll", recalcRects);
  }, [recalcRects]);

  // Scroll current match into view
  useEffect(() => {
    if (currentIndex <= 0 || currentIndex > matches.length) return;

    const match = matches[currentIndex - 1];
    const rect = match.range.getBoundingClientRect();
    const container = containerRef.current;
    if (!container) return;

    const containerRect = container.getBoundingClientRect();
    const isVisible =
      rect.top >= containerRect.top &&
      rect.bottom <= containerRect.bottom;

    if (!isVisible) {
      const scrollTarget = rect.top - containerRect.top + container.scrollTop - container.clientHeight / 2;
      container.scrollTo({ top: scrollTarget, behavior: "smooth" });
    }

    // Recalc after scroll
    setTimeout(recalcRects, 200);
  }, [currentIndex, matches, recalcRects]);

  // Reset on close
  useEffect(() => {
    if (!isSearchOpen) {
      setQuery("");
      setMatches([]);
      setCurrentIndex(0);
    }
  }, [isSearchOpen]);

  function handleNext() {
    if (matches.length === 0) return;
    setCurrentIndex((prev) => (prev >= matches.length ? 1 : prev + 1));
  }

  function handlePrevious() {
    if (matches.length === 0) return;
    setCurrentIndex((prev) => (prev <= 1 ? matches.length : prev - 1));
  }

  function handleClose() {
    setQuery("");
    setMatches([]);
    setCurrentIndex(0);
    onClose();
  }

  return (
    <div className={`relative flex flex-1 flex-col overflow-hidden ${className ?? ""}`}>
      {isSearchOpen && (
        <FindBar
          query={query}
          onQueryChange={setQuery}
          currentMatch={currentIndex}
          totalMatches={matches.length}
          onNext={handleNext}
          onPrevious={handlePrevious}
          onClose={handleClose}
        />
      )}
      <div ref={containerRef} className="relative flex-1 overflow-y-auto">
        {children}
        {/* Highlight overlay */}
        {matches.length > 0 && (
          <div
            className="pointer-events-none absolute inset-0"
            style={{ zIndex: 10 }}
          >
            {matches.flatMap((match, matchIdx) =>
              match.rects.map((rect, rectIdx) => (
                <div
                  key={`${matchIdx}-${rectIdx}`}
                  style={{
                    position: "absolute",
                    top: rect.top,
                    left: rect.left,
