interface SearchableContainerProps {
  isSearchOpen: boolean;
  onClose: () => void;
  children: React.ReactNode;
  className?: string;
}

/**
 * Count text matches within a container using TreeWalker.
 */
function countMatches(container: HTMLElement, query: string): number {
  if (!query) return 0;

  const lowerQuery = query.toLowerCase();
  let count = 0;
  const walker = document.createTreeWalker(
    container,
    NodeFilter.SHOW_TEXT,
    null
  );

  let node: Text | null;
  while ((node = walker.nextNode() as Text | null)) {
    const text = (node.textContent ?? "").toLowerCase();
    let idx = 0;
    while (idx < text.length) {
      const found = text.indexOf(lowerQuery, idx);
      if (found === -1) break;
      count++;
      idx = found + lowerQuery.length;
    }
  }

  return count;
}

/**
 * Navigate to a specific match using window.find().
 * Resets selection to the start of the container first,
 * then calls window.find() `targetIndex` times.
 */
function navigateToMatch(
  container: HTMLElement,
  query: string,
  targetIndex: number,
  backwards: boolean = false
): boolean {
  if (!query || targetIndex < 1) return false;

  // Clear current selection and move to start of container
  const sel = window.getSelection();
  if (!sel) return false;

  if (!backwards) {
    // Collapse selection to start of container so find() starts from top
    const range = document.createRange();
    range.selectNodeContents(container);
    range.collapse(true); // collapse to start
    sel.removeAllRanges();
    sel.addRange(range);

    // Walk forward to the target match
    for (let i = 0; i < targetIndex; i++) {
      // @ts-expect-error - window.find is non-standard but available in WebKit/Blink
      const found = window.find(query, false, false, true, false, false, false);
      if (!found) return false;
    }
  } else {
    // Collapse to end for backwards search
    const range = document.createRange();
    range.selectNodeContents(container);
    range.collapse(false); // collapse to end
    sel.removeAllRanges();
    sel.addRange(range);

    // @ts-expect-error - window.find is non-standard
    const found = window.find(query, false, true, true, false, false, false);
    return found;
  }

  return true;
}

export function SearchableContainer({
  isSearchOpen,
  onClose,
  children,
  className,
}: SearchableContainerProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [query, setQuery] = useState("");
  const [totalMatches, setTotalMatches] = useState(0);
  const [currentIndex, setCurrentIndex] = useState(0);
  const debounceRef = useRef<ReturnType<typeof setTimeout>>();

  // Count matches when query changes
  useEffect(() => {
    clearTimeout(debounceRef.current);

    if (!query || !containerRef.current) {
      setTotalMatches(0);
      setCurrentIndex(0);
      return;
    }

    debounceRef.current = setTimeout(() => {
      if (!containerRef.current) return;
      const count = countMatches(containerRef.current, query);
      setTotalMatches(count);
      if (count > 0) {
        setCurrentIndex(1);
        navigateToMatch(containerRef.current, query, 1);
      } else {
        setCurrentIndex(0);
      }
    }, 150);

    return () => clearTimeout(debounceRef.current);
  }, [query]);

  const handleNext = useCallback(() => {
    if (totalMatches === 0 || !containerRef.current) return;
    const next = currentIndex >= totalMatches ? 1 : currentIndex + 1;
    setCurrentIndex(next);
    navigateToMatch(containerRef.current, query, next);
  }, [totalMatches, currentIndex, query]);

  const handlePrevious = useCallback(() => {
    if (totalMatches === 0 || !containerRef.current) return;
    const prev = currentIndex <= 1 ? totalMatches : currentIndex - 1;
    setCurrentIndex(prev);
    navigateToMatch(containerRef.current, query, prev);
  }, [totalMatches, currentIndex, query]);

  const handleClose = useCallback(() => {
    setQuery("");
    setTotalMatches(0);
    setCurrentIndex(0);
    // Clear the native selection highlight
    window.getSelection()?.removeAllRanges();
    onClose();
  }, [onClose]);

  // Reset on close
  useEffect(() => {
    if (!isSearchOpen) {
      setQuery("");
      setTotalMatches(0);
      setCurrentIndex(0);
      window.getSelection()?.removeAllRanges();
    }
  }, [isSearchOpen]);

  return (
    <div className={`relative ${className ?? ""}`} ref={containerRef}>
      {isSearchOpen && (
        <div className="absolute right-0 top-0 z-20">
          <FindBar
            query={query}
            onQueryChange={setQuery}
            currentMatch={currentIndex}
            totalMatches={totalMatches}
            onNext={handleNext}
            onPrevious={handlePrevious}
            onClose={handleClose}
          />
        </div>
      )}
      {children}
    </div>
  );
}

