import { useEffect, useRef } from "react";
import { ChevronUp, ChevronDown, X } from "lucide-react";

interface FindBarProps {
  query: string;
  onQueryChange: (query: string) => void;
  currentMatch: number;
  totalMatches: number;
  onNext: () => void;
  onPrevious: () => void;
  onClose: () => void;
}

export function FindBar({
  query,
  onQueryChange,
  currentMatch,
  totalMatches,
  onNext,
  onPrevious,
  onClose,
}: FindBarProps) {
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  function handleKeyDown(e: React.KeyboardEvent) {
    if (e.key === "Escape") {
      e.preventDefault();
      onClose();
    } else if (e.key === "Enter" && e.shiftKey) {
      e.preventDefault();
      onPrevious();
    } else if (e.key === "Enter") {
      e.preventDefault();
      onNext();
    }
  }

  return (
    <div className="flex items-center gap-2 border-b border-border-subtle bg-bg-overlay px-3 py-1.5">
      <input
        ref={inputRef}
        type="text"
        value={query}
        onChange={(e) => onQueryChange(e.target.value)}
        onKeyDown={handleKeyDown}
        placeholder="Find..."
        className="h-6 w-52 rounded border border-border-subtle bg-bg px-2 text-xs text-fg placeholder:text-fg-faint focus:border-accent focus:outline-none"
      />
      <span className="min-w-[60px] text-[11px] text-fg-subtle">
        {query
          ? totalMatches > 0
            ? `${currentMatch} of ${totalMatches}`
            : "No results"
          : ""}
      </span>
      <button
        onClick={onPrevious}
        disabled={totalMatches === 0}
        className="flex h-5 w-5 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg disabled:opacity-30"
        title="Previous match (Shift+Enter)"
      >
        <ChevronUp size={14} />
      </button>
      <button
        onClick={onNext}
        disabled={totalMatches === 0}
        className="flex h-5 w-5 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg disabled:opacity-30"
        title="Next match (Enter)"
      >
        <ChevronDown size={14} />
      </button>
      <button
        onClick={onClose}
        className="flex h-5 w-5 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg"
        title="Close (Escape)"
      >
        <X size={14} />
      </button>
    </div>
  );
}

