use std::ffi::{c_void, CString};
use std::ptr;
use std::sync::atomic::{AtomicPtr, Ordering};

use objc2::rc::Retained;
use objc2::runtime::{AnyObject, Sel};
use objc2::{define_class, msg_send, DefinedClass, MainThreadMarker, MainThreadOnly};
use objc2_app_kit::{NSEvent, NSEventModifierFlags, NSView, NSWindow};

use super::{
    GhosttyInputAction, GhosttyInputKey, GhosttyInputMods, GhosttyMouseButton, GhosttyMouseState,
    GhosttyScrollMods,
};

fn debug_log(msg: &str) {
    use std::io::Write;

    let timestamp = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap_or_default();
    let line = format!(
        "[{}.{:03}] {}\n",
        timestamp.as_secs(),
        timestamp.subsec_millis(),
        msg
    );
    if let Ok(mut f) = std::fs::OpenOptions::new()
        .create(true)
        .append(true)
        .open("/tmp/entire-terminal-debug.log")
    {
        let _ = f.write_all(line.as_bytes());
    }
}

#[derive(Default)]
struct GhosttyHostViewIvars {
    surface: AtomicPtr<c_void>,
}

fn mods_from_event(event: &NSEvent) -> GhosttyInputMods {
    let flags = event.modifierFlags();
    let mut mods = GhosttyInputMods::NONE;

    if flags.contains(NSEventModifierFlags::Shift) {
        mods |= GhosttyInputMods::SHIFT;
    }
    if flags.contains(NSEventModifierFlags::Control) {
        mods |= GhosttyInputMods::CTRL;
    }
    if flags.contains(NSEventModifierFlags::Option) {
        mods |= GhosttyInputMods::ALT;
    }
    if flags.contains(NSEventModifierFlags::Command) {
        mods |= GhosttyInputMods::SUPER;
    }

    mods
}

fn consumed_mods_for_event(surface: *mut c_void, event: &NSEvent) -> GhosttyInputMods {
    let translated =
        unsafe { super::ghostty_surface_key_translation_mods(surface, mods_from_event(event)) };
    let mut consumed = GhosttyInputMods::NONE;

    if translated.contains(GhosttyInputMods::SHIFT) {
        consumed |= GhosttyInputMods::SHIFT;
    }
    if translated.contains(GhosttyInputMods::ALT) {
        consumed |= GhosttyInputMods::ALT;
    }

    consumed
}

fn text_for_key_event(event: &NSEvent) -> Option<String> {
    let chars = event.characters()?.to_string();
    if chars.is_empty() {
        return None;
    }

    if chars.chars().count() == 1 {
        let scalar = chars.chars().next()? as u32;
        if scalar < 0x20
            && event
                .modifierFlags()
                .contains(NSEventModifierFlags::Control)
        {
            return event
                .charactersIgnoringModifiers()
                .map(|text| text.to_string());
        }
        if (0xF700..=0xF8FF).contains(&scalar) {
            return None;
        }
    }

    Some(chars)
}

fn should_send_text(text: &str) -> bool {
    match text.chars().next() {
        Some(ch) => (ch as u32) >= 0x20,
        None => false,
    }
}

fn unshifted_codepoint_from_event(event: &NSEvent) -> u32 {
    event
        .charactersIgnoringModifiers()
        .or_else(|| event.characters())
        .and_then(|text| text.to_string().chars().next())
        .map(|ch| ch as u32)
        .unwrap_or(0)
}

fn matches_command_shortcut(event: &NSEvent, key: char) -> bool {
    let flags = event.modifierFlags();
    if !flags.contains(NSEventModifierFlags::Command) {
        return false;
    }
    if flags.contains(NSEventModifierFlags::Control) || flags.contains(NSEventModifierFlags::Option)
    {
        return false;
    }

    event
        .charactersIgnoringModifiers()
        .map(|text| text.to_string())
        .map(|text| text.eq_ignore_ascii_case(&key.to_string()))
        .unwrap_or(false)
}

fn paste_clipboard_text(surface: *mut c_void) -> bool {
    let Some(text) = super::system_clipboard_text().filter(|text| !text.is_empty()) else {
        return false;
    };

    let c_text = CString::new(text.as_str()).unwrap_or_default();
    unsafe {
        super::ghostty_surface_text(surface, c_text.as_ptr(), text.len());
    }
    true
}

fn send_key_event(surface: *mut c_void, event: &NSEvent) -> bool {
    let mut key = GhosttyInputKey {
        action: if event.isARepeat() {
            GhosttyInputAction::Repeat
        } else {
            GhosttyInputAction::Press
        },
        mods: mods_from_event(event),
        consumed_mods: consumed_mods_for_event(surface, event),
        keycode: event.keyCode() as u32,
        text: ptr::null(),
        unshifted_codepoint: unshifted_codepoint_from_event(event),
        composing: false,
    };

    if let Some(text) = text_for_key_event(event).filter(|text| should_send_text(text)) {
        let c_text = CString::new(text).unwrap_or_default();
        key.text = c_text.as_ptr();
        unsafe { super::ghostty_surface_key(surface, key) }
    } else {
        unsafe { super::ghostty_surface_key(surface, key) }
    }
}

define_class!(
    #[unsafe(super(NSView))]
    #[thread_kind = MainThreadOnly]
    #[ivars = GhosttyHostViewIvars]
    #[name = "EntireGhosttyHostView"]
    struct GhosttyHostView;

    impl GhosttyHostView {
        #[unsafe(method(acceptsFirstResponder))]
        fn accepts_first_responder(&self) -> bool {
            true
        }

        #[unsafe(method(becomeFirstResponder))]
        fn become_first_responder(&self) -> bool {
            let result: bool = unsafe { msg_send![super(self), becomeFirstResponder] };
            if result {
                let surface = self.surface();
                if !surface.is_null() {
                    unsafe { super::ghostty_surface_set_focus(surface, true) };
                }
            }
            result
        }

        #[unsafe(method(resignFirstResponder))]
        fn resign_first_responder(&self) -> bool {
            let result: bool = unsafe { msg_send![super(self), resignFirstResponder] };
            if result {
                let surface = self.surface();
                if !surface.is_null() {
                    unsafe { super::ghostty_surface_set_focus(surface, false) };
                }
            }
            result
        }

        #[unsafe(method(mouseDown:))]
        fn mouse_down(&self, event: &NSEvent) {
            if let Some(window) = self.window() {
                let _: bool = unsafe { msg_send![&*window, makeFirstResponder: self] };
            }

            let surface = self.surface();
            if !surface.is_null() {
                let point = self.convertPoint_fromView(event.locationInWindow(), None);
                let y = self.bounds().size.height - point.y;
                let mods = mods_from_event(event);
                unsafe {
                    super::ghostty_surface_mouse_pos(surface, point.x, y, mods);
                    let _ = super::ghostty_surface_mouse_button(
                        surface,
                        GhosttyMouseState::Press,
                        GhosttyMouseButton::Left,
                        mods,
                    );
                }
            } else {
                unsafe { msg_send![super(self), mouseDown: event] }
            }
        }

        #[unsafe(method(mouseUp:))]
        fn mouse_up(&self, event: &NSEvent) {
            let surface = self.surface();
            if !surface.is_null() {
                let point = self.convertPoint_fromView(event.locationInWindow(), None);
                let y = self.bounds().size.height - point.y;
                let mods = mods_from_event(event);
                unsafe {
                    super::ghostty_surface_mouse_pos(surface, point.x, y, mods);
                    let _ = super::ghostty_surface_mouse_button(
                        surface,
                        GhosttyMouseState::Release,
                        GhosttyMouseButton::Left,
                        mods,
                    );
                }
            } else {
                unsafe { msg_send![super(self), mouseUp: event] }
            }
        }

        #[unsafe(method(mouseDragged:))]
        fn mouse_dragged(&self, event: &NSEvent) {
            let surface = self.surface();
            if !surface.is_null() {
                let point = self.convertPoint_fromView(event.locationInWindow(), None);
                let y = self.bounds().size.height - point.y;
                let mods = mods_from_event(event);
                unsafe {
                    super::ghostty_surface_mouse_pos(surface, point.x, y, mods);
                }
            } else {
                unsafe { msg_send![super(self), mouseDragged: event] }
            }
        }

        #[unsafe(method(rightMouseDown:))]
        fn right_mouse_down(&self, event: &NSEvent) {
            let surface = self.surface();
            if !surface.is_null() {
                let point = self.convertPoint_fromView(event.locationInWindow(), None);
                let y = self.bounds().size.height - point.y;
                let mods = mods_from_event(event);
                unsafe {
                    super::ghostty_surface_mouse_pos(surface, point.x, y, mods);
                    let _ = super::ghostty_surface_mouse_button(
                        surface,
                        GhosttyMouseState::Press,
                        GhosttyMouseButton::Right,
                        mods,
                    );
                }
            } else {
                unsafe { msg_send![super(self), rightMouseDown: event] }
            }
        }

        #[unsafe(method(rightMouseUp:))]
        fn right_mouse_up(&self, event: &NSEvent) {
            let surface = self.surface();
            if !surface.is_null() {
                let point = self.convertPoint_fromView(event.locationInWindow(), None);
                let y = self.bounds().size.height - point.y;
                let mods = mods_from_event(event);
                unsafe {
                    super::ghostty_surface_mouse_pos(surface, point.x, y, mods);
                    let _ = super::ghostty_surface_mouse_button(
                        surface,
                        GhosttyMouseState::Release,
                        GhosttyMouseButton::Right,
                        mods,
                    );
                }
            } else {
                unsafe { msg_send![super(self), rightMouseUp: event] }
            }
        }

        #[unsafe(method(rightMouseDragged:))]
        fn right_mouse_dragged(&self, event: &NSEvent) {
            let surface = self.surface();
            if !surface.is_null() {
                let point = self.convertPoint_fromView(event.locationInWindow(), None);
                let y = self.bounds().size.height - point.y;
                let mods = mods_from_event(event);
                unsafe {
                    super::ghostty_surface_mouse_pos(surface, point.x, y, mods);
                }
            } else {
                unsafe { msg_send![super(self), rightMouseDragged: event] }
            }
        }

        #[unsafe(method(scrollWheel:))]
        fn scroll_wheel(&self, event: &NSEvent) {
            let surface = self.surface();
            if !surface.is_null() {
                if let Some(window) = self.window() {
                    let _: bool = unsafe { msg_send![&*window, makeFirstResponder: self] };
                }

                let point = self.convertPoint_fromView(event.locationInWindow(), None);
                let y = self.bounds().size.height - point.y;
                let mods = mods_from_event(event);
                let scroll_mods = GhosttyScrollMods {
                    precision: event.hasPreciseScrollingDeltas(),
                };

                unsafe {
                    super::ghostty_surface_set_focus(surface, true);
                    super::ghostty_surface_mouse_pos(surface, point.x, y, mods);
                    super::ghostty_surface_mouse_scroll(
                        surface,
                        event.scrollingDeltaX(),
                        event.scrollingDeltaY(),
                        scroll_mods,
                    );
                }
            } else {
                unsafe { msg_send![super(self), scrollWheel: event] }
            }
        }

        #[unsafe(method(keyDown:))]
        fn key_down(&self, event: &NSEvent) {
            let surface = self.surface();
            if !surface.is_null() {
                unsafe { super::ghostty_surface_set_focus(surface, true) };
                if matches_command_shortcut(event, 'v') && paste_clipboard_text(surface) {
                    debug_log("ghostty_host_view: handled command+v via system pasteboard");
                    return;
                }
                if matches_command_shortcut(event, 'c') {
                    // Forward Cmd+C to ghostty — it will trigger
                    // runtime_write_clipboard if there is a selection.
                    let handled = send_key_event(surface, event);
                    debug_log(&format!(
                        "ghostty_host_view: handled command+c, ghostty_handled={}",
                        handled,
                    ));
                    return;
                }
                let handled = send_key_event(surface, event);
                let text = event
                    .characters()
                    .map(|chars| chars.to_string())
                    .unwrap_or_default();
                debug_log(&format!(
                    "ghostty_host_view: keyDown keyCode={} handled={} chars={:?}",
                    event.keyCode(),
                    handled,
                    text,
                ));
                if handled {
                    return;
                }
            }

            unsafe { msg_send![super(self), keyDown: event] }
        }

        #[unsafe(method(copy:))]
        fn copy(&self, _sender: Option<&AnyObject>) {
            let surface = self.surface();
            if !surface.is_null() {
                let key = GhosttyInputKey {
                    action: GhosttyInputAction::Press,
                    mods: GhosttyInputMods::SUPER,
                    consumed_mods: GhosttyInputMods::NONE,
                    keycode: 8, // macOS keycode for 'c'
                    text: ptr::null(),
                    unshifted_codepoint: 'c' as u32,
                    composing: false,
                };
                unsafe { super::ghostty_surface_key(surface, key); }
            }
        }

        #[unsafe(method(paste:))]
        fn paste(&self, _sender: Option<&AnyObject>) {
            let surface = self.surface();
            if !surface.is_null() {
                unsafe { super::ghostty_surface_set_focus(surface, true) };
                let _ = paste_clipboard_text(surface);
            }
        }

        #[unsafe(method(doCommandBySelector:))]
        fn do_command_by_selector(&self, _selector: Sel) {
            // Prevent NSBeep for commands we intentionally leave to Ghostty.
        }
    }
);

impl GhosttyHostView {
    fn new(mtm: MainThreadMarker, frame: objc2_foundation::NSRect) -> Retained<Self> {
        let this = Self::alloc(mtm).set_ivars(GhosttyHostViewIvars::default());
        unsafe { msg_send![super(this), initWithFrame: frame] }
    }

    fn surface(&self) -> *mut c_void {
        self.ivars().surface.load(Ordering::Relaxed)
    }

    fn set_surface(&self, surface: *mut c_void) {
        self.ivars().surface.store(surface, Ordering::Relaxed);
    }

    fn clear_surface(&self) {
        self.set_surface(ptr::null_mut());
    }
}

/// Manages a native NSView overlay positioned on top of the Tauri webview.
/// Ghostty renders into this view via its own Metal infrastructure.
pub struct GhosttyOverlay {
    /// The NSView that contains the Metal layer. libghostty renders into this.
    view: Retained<GhosttyHostView>,
    /// Track visibility so we avoid redundant show/hide calls.
    visible: bool,
}

// SAFETY: NSView operations are dispatched on the main thread via objc2.
// The overlay is only mutated through Mutex<GhosttyState>.
unsafe impl Send for GhosttyOverlay {}
unsafe impl Sync for GhosttyOverlay {}

impl GhosttyOverlay {
    /// Create a new overlay NSView and add it as a subview of the given window.
    ///
    /// # Safety
    /// Must be called on the main thread. `window` must be a valid NSWindow pointer.
    pub unsafe fn new(window: *mut c_void) -> Result<Self, String> {
        // We must be on the main thread to create NSView
        let mtm = MainThreadMarker::new()
            .ok_or_else(|| "Must be called on the main thread".to_string())?;

        let window: &NSWindow = unsafe { &*(window as *const NSWindow) };
        let content_view = window
            .contentView()
            .ok_or_else(|| "Window has no contentView".to_string())?;

        // Create the overlay NSView
        let frame = content_view.frame();
        let view = GhosttyHostView::new(mtm, frame);

        // Enable layer-backing (required for ghostty's Metal rendering)
        // but do NOT pre-create a CAMetalLayer — ghostty sets up its own
        // rendering infrastructure on the view internally.
        view.setWantsLayer(true);

        // Add as subview — on top of the webview content
        content_view.addSubview(&view);

        // Start hidden until explicitly shown
        view.setHidden(true);

        Ok(Self {
            view,
            visible: false,
        })
    }

    /// Returns the raw NSView pointer for passing to libghostty's surface config.
    pub fn nsview_ptr(&self) -> *mut c_void {
        let view_ref: &NSView = &self.view;
        view_ref as *const NSView as *mut c_void
    }

    pub fn set_surface(&self, surface: *mut c_void) {
        self.view.set_surface(surface);
    }

    pub fn clear_surface(&self) {
        self.view.clear_surface();
    }

    /// Reposition and resize the overlay to match the terminal panel in the webview.
    ///
    /// Coordinates come from the frontend (top-left origin, CSS pixels).
    /// macOS NSView uses bottom-left origin, so we flip Y.
    pub fn update_frame(&self, x: f64, y: f64, width: f64, height: f64) {
        if let Some(superview) = unsafe { self.view.superview() } {
            let parent_height = superview.frame().size.height;
            // Convert from top-left (web) to bottom-left (macOS) origin
            let flipped_y = parent_height - y - height;

            let frame = objc2_foundation::NSRect::new(
                objc2_foundation::NSPoint::new(x, flipped_y),
                objc2_foundation::NSSize::new(width, height),
            );
            self.view.setFrame(frame);
        }
    }

    /// Show or hide the overlay.
    pub fn set_visible(&mut self, visible: bool) {
        if self.visible != visible {
            self.view.setHidden(!visible);
            self.visible = visible;
        }
    }

    /// Whether the overlay is currently visible.
    #[allow(dead_code)]
    pub fn is_visible(&self) -> bool {
        self.visible
    }

    /// Make the overlay the first responder (receive keyboard input).
    pub fn focus(&self) -> bool {
        unsafe {
            if let Some(window) = self.view.window() {
                let result: bool = msg_send![&*window, makeFirstResponder: &*self.view];
                return result;
            }
        }
        false
    }
}

impl Drop for GhosttyOverlay {
    fn drop(&mut self) {
        // Remove from superview to clean up
        self.view.removeFromSuperview();
    }
}

/// Get the raw NSWindow pointer from a Tauri webview window.
pub fn get_nswindow(window: &tauri::WebviewWindow) -> Result<*mut c_void, String> {
    #[cfg(target_os = "macos")]
    {
        use raw_window_handle::{HasWindowHandle, RawWindowHandle};

        let handle = window
            .window_handle()
            .map_err(|e| format!("Failed to get window handle: {}", e))?;

        match handle.as_raw() {
            RawWindowHandle::AppKit(handle) => {
                // ns_view is the content view — we need the window.
                // Get the window from the view.
                let ns_view = handle.ns_view.as_ptr() as *mut c_void;
                let ns_window: *mut c_void =
                    unsafe { msg_send![ns_view as *mut AnyObject, window] };
                Ok(ns_window)
            }
            _ => Err("Expected AppKit window handle on macOS".into()),
        }
    }

    #[cfg(not(target_os = "macos"))]
    {
        let _ = window;
        Err("NSView overlay is only supported on macOS".into())
    }
}

