// Runtime callbacks (C ABI)
// ---------------------------------------------------------------------------

extern "C" fn runtime_wakeup(_userdata: *mut c_void) {
    // Trigger a redraw on the main thread. For now, this is a no-op
    // since we drive rendering from the Tauri event loop.
}

extern "C" fn runtime_action(
    _app: *mut c_void,
    _target: GhosttyTarget,
    _action: GhosttyAction,
) -> bool {
    // Handle ghostty actions (new tab, close, etc.)
    // Return false to indicate we didn't handle it
    false
}

extern "C" fn runtime_read_clipboard(
    _userdata: *mut c_void,
    _clipboard: GhosttyClipboard,
    _state: *mut c_void,
) -> bool {
    // TODO: integrate with system clipboard via Tauri
    false
}

extern "C" fn runtime_confirm_read_clipboard(
    _userdata: *mut c_void,
    _content: *const c_char,
    _state: *mut c_void,
    _request: GhosttyClipboardRequest,
) {
    // Auto-confirm clipboard reads for embedded context
}

extern "C" fn runtime_write_clipboard(
    _userdata: *mut c_void,
    _clipboard: GhosttyClipboard,
    content: *const GhosttyClipboardContent,
    content_len: usize,
    _confirm: bool,
) {
    debug_log(&format!(
        "runtime_write_clipboard: content={:?}, content_len={}",
        content, content_len
    ));
    if let Some(text) = decode_clipboard_text(content, content_len) {
        debug_log(&format!(
            "runtime_write_clipboard: writing {} bytes to clipboard",
            text.len()
        ));
        let _ = write_system_clipboard_text(&text);
        debug_log("runtime_write_clipboard: done");
    }
}

extern "C" fn runtime_close_surface(_userdata: *mut c_void, _process_alive: bool) {
    // Surface closed — the frontend will handle cleanup via destroy_surface
}

#[cfg(test)]
mod tests {
    use super::{
        decode_clipboard_text, GhosttyClipboardRequest, GhosttyInputKey, GhosttyMouseButton,
        GhosttyMouseState, GhosttyPlatform, GhosttyScrollMods, GhosttySurfaceConfig,
    };
    use std::ffi::CString;

    #[test]
    fn ghostty_surface_config_matches_binary_size() {
        assert_eq!(std::mem::size_of::<GhosttySurfaceConfig>(), 112);
    }

    #[test]
    fn ghostty_platform_enum_matches_binary_values() {
        assert_eq!(GhosttyPlatform::MacOS as u32, 1);
    }

    #[test]
    fn ghostty_input_key_matches_binary_layout() {
        assert_eq!(std::mem::size_of::<GhosttyInputKey>(), 32);
        assert_eq!(std::mem::align_of::<GhosttyInputKey>(), 8);
    }

    #[test]
    fn ghostty_scroll_mods_matches_binary_layout() {
        assert_eq!(
            std::mem::size_of::<GhosttyScrollMods>(),
            std::mem::size_of::<bool>()
        );
        assert_eq!(
            std::mem::align_of::<GhosttyScrollMods>(),
            std::mem::align_of::<bool>()
        );
    }

    #[test]
    fn ghostty_input_enums_match_binary_values() {
        assert_eq!(GhosttyMouseState::Release as u32, 0);
        assert_eq!(GhosttyMouseState::Press as u32, 1);
        assert_eq!(GhosttyMouseButton::Left as u32, 1);
        assert_eq!(GhosttyMouseButton::Right as u32, 2);
        assert_eq!(GhosttyMouseButton::Middle as u32, 3);
        assert_eq!(GhosttyClipboardRequest::Osc52Write as u32, 2);
    }

    #[test]
    fn decodes_clipboard_chunks_into_utf8_text() {
        let first = CString::new("hello ").unwrap();
        let second = CString::new("world").unwrap();
        let chunks = [
            super::GhosttyClipboardContent {
                data: first.as_ptr(),
                len: 6,
            },
            super::GhosttyClipboardContent {
                data: second.as_ptr(),
                len: 5,
            },
        ];

        assert_eq!(
            decode_clipboard_text(chunks.as_ptr(), chunks.len()).as_deref(),
            Some("hello world")
        );
    }
}

