const isSplit = activeTerminalTab.panes.length > 1;
const paneFlexBasis = isSplit
  ? paneIndex === 0
    ? `${activeTerminalTab.splitRatio * 100}%`
    : `${(1 - activeTerminalTab.splitRatio) * 100}%`
  : undefined;
return (
  <React.Fragment key={pane.id}>
    {paneIndex === 1 && isSplit && (
      <div
        onMouseDown={(e) => {
          e.preventDefault();
          if (!activeTerminalTab) return;
          const tabId = activeTerminalTab.id;
          const isHorizontal = activeTerminalTab.splitDirection === "horizontal";
          const container = e.currentTarget.parentElement;
          if (!container) return;
          const rect = container.getBoundingClientRect();

          function onMouseMove(ev: MouseEvent) {
            const ratio = isHorizontal
              ? (ev.clientY - rect.top) / rect.height
              : (ev.clientX - rect.left) / rect.width;
            onWorkspaceChange((currentWorkspace) =>
              setSplitRatioInTerminalTab(currentWorkspace, tabId, ratio)
            );
          }
          function onMouseUp() {
            window.removeEventListener("mousemove", onMouseMove);
            window.removeEventListener("mouseup", onMouseUp);
          }
          window.addEventListener("mousemove", onMouseMove);
          window.addEventListener("mouseup", onMouseUp);
        }}
        className={`shrink-0 bg-border transition-colors hover:bg-accent ${
          activeTerminalTab.splitDirection === "horizontal"
            ? "h-[3px] cursor-row-resize"
            : "w-[3px] cursor-col-resize"
        }`}
      />

