fn decode_clipboard_text(
    content: *const GhosttyClipboardContent,
    content_len: usize,
) -> Option<String> {
    if content.is_null() || content_len == 0 {
        return None;
    }

    let chunks = unsafe { std::slice::from_raw_parts(content, content_len) };
    let total_len = chunks.iter().map(|chunk| chunk.len).sum();
    let mut bytes = Vec::with_capacity(total_len);

    for chunk in chunks {
        if chunk.data.is_null() || chunk.len == 0 {
            continue;
        }

        let part = unsafe { std::slice::from_raw_parts(chunk.data as *const u8, chunk.len) };
        bytes.extend_from_slice(part);
    }

    String::from_utf8(bytes).ok()
}

pub(super) fn system_clipboard_text() -> Option<String> {
    let pasteboard = NSPasteboard::generalPasteboard();
    pasteboard
        .stringForType(unsafe { NSPasteboardTypeString })
        .map(|text| text.to_string())
}

fn write_system_clipboard_text(text: &str) -> bool {
    let pasteboard = NSPasteboard::generalPasteboard();
    pasteboard.clearContents();
    let text = NSString::from_str(text);
    pasteboard.setString_forType(&text, unsafe { NSPasteboardTypeString })
}

