    fn new(mtm: MainThreadMarker, frame: objc2_foundation::NSRect) -> Retained<Self> {
        let this = Self::alloc(mtm).set_ivars(GhosttyHostViewIvars::default());
        unsafe { msg_send![super(this), initWithFrame: frame] }
    }

    fn surface(&self) -> *mut c_void {
        self.ivars().surface.load(Ordering::Relaxed)
    }

    fn set_surface(&self, surface: *mut c_void) {
        self.ivars().surface.store(surface, Ordering::Relaxed);
