 28→fn generate_surface_id() -> String {
 29→    use std::time::{SystemTime, UNIX_EPOCH};
 30→    let now = SystemTime::now()
 31→        .duration_since(UNIX_EPOCH)
 32→        .unwrap_or_default();
 33→    format!("ghostty-{}-{}", now.as_secs(), now.subsec_nanos())
 34→}
