385→                if matches_command_shortcut(event, 'c') {
386→                    // Forward Cmd+C to ghostty — it will trigger
387→                    // runtime_write_clipboard if there is a selection.
388→                    let handled = send_key_event(surface, event);
389→                    debug_log(&format!(
