395→                let handled = send_key_event(surface, event);
396→                let text = event
397→                    .characters()
398→                    .map(|chars| chars.to_string())
399→                    .unwrap_or_default();
400→                debug_log(&format!(
401→                    "ghostty_host_view: keyDown keyCode={} handled={} chars={:?}",
402→                    event.keyCode(),
403→                    handled,
404→                    text,
405→                ));
406→                if handled {
407→                    return;
408→                }
409→            }
410→
411→            unsafe { msg_send![super(self), keyDown: event] }
412→        }
