466→/// Manages a native NSView overlay positioned on top of the Tauri webview.
467→/// Ghostty renders into this view via its own Metal infrastructure.
468→pub struct GhosttyOverlay {
469→    /// The NSView that contains the Metal layer. libghostty renders into this.
470→    view: Retained<GhosttyHostView>,
471→    /// Track visibility so we avoid redundant show/hide calls.
472→    visible: bool,
473→}
474→
475→// SAFETY: NSView operations are dispatched on the main thread via objc2.
476→// The overlay is only mutated through Mutex<GhosttyState>.
477→unsafe impl Send for GhosttyOverlay {}
478→unsafe impl Sync for GhosttyOverlay {}
479→
480→impl GhosttyOverlay {
481→    /// Create a new overlay NSView and add it as a subview of the given window.
482→    ///
483→    /// # Safety
484→    /// Must be called on the main thread. `window` must be a valid NSWindow pointer.
485→    pub unsafe fn new(window: *mut c_void) -> Result<Self, String> {
486→        // We must be on the main thread to create NSView
487→        let mtm = MainThreadMarker::new()
488→            .ok_or_else(|| "Must be called on the main thread".to_string())?;
489→
490→        let window: &NSWindow = unsafe { &*(window as *const NSWindow) };
491→        let content_view = window
492→            .contentView()
493→            .ok_or_else(|| "Window has no contentView".to_string())?;
494→
495→        // Create the overlay NSView
496→        let frame = content_view.frame();
497→        let view = GhosttyHostView::new(mtm, frame);
498→
499→        // Enable layer-backing (required for ghostty's Metal rendering)
500→        // but do NOT pre-create a CAMetalLayer — ghostty sets up its own
501→        // rendering infrastructure on the view internally.
502→        view.setWantsLayer(true);
503→
504→        // Add as subview — on top of the webview content
505→        content_view.addSubview(&view);
506→
507→        // Start hidden until explicitly shown
508→        view.setHidden(true);
509→
510→        Ok(Self {
511→            view,
512→            visible: false,
513→        })
514→    }
515→
516→    /// Returns the raw NSView pointer for passing to libghostty's surface config.
517→    pub fn nsview_ptr(&self) -> *mut c_void {
518→        let view_ref: &NSView = &self.view;
519→        view_ref as *const NSView as *mut c_void
520→    }
521→
522→    pub fn set_surface(&self, surface: *mut c_void) {
523→        self.view.set_surface(surface);
524→    }
525→
526→    pub fn clear_surface(&self) {
527→        self.view.clear_surface();
528→    }
529→
530→    /// Reposition and resize the overlay to match the terminal panel in the webview.
531→    ///
532→    /// Coordinates come from the frontend (top-left origin, CSS pixels).
533→    /// macOS NSView uses bottom-left origin, so we flip Y.
534→    pub fn update_frame(&self, x: f64, y: f64, width: f64, height: f64) {
535→        if let Some(superview) = unsafe { self.view.superview() } {
536→            let parent_height = superview.frame().size.height;
537→            // Convert from top-left (web) to bottom-left (macOS) origin
538→            let flipped_y = parent_height - y - height;
539→
540→            let frame = objc2_foundation::NSRect::new(
541→                objc2_foundation::NSPoint::new(x, flipped_y),
542→                objc2_foundation::NSSize::new(width, height),
543→            );
544→            self.view.setFrame(frame);
545→        }
546→    }
547→
548→    /// Show or hide the overlay.
549→    pub fn set_visible(&mut self, visible: bool) {
550→        if self.visible != visible {
551→            self.view.setHidden(!visible);
552→            self.visible = visible;
553→        }
554→    }
555→
556→    /// Whether the overlay is currently visible.
557→    #[allow(dead_code)]
558→    pub fn is_visible(&self) -> bool {
559→        self.visible
560→    }
561→
562→    /// Make the overlay the first responder (receive keyboard input).
563→    pub fn focus(&self) -> bool {
564→        unsafe {
565→            if let Some(window) = self.view.window() {
566→                let result: bool = msg_send![&*window, makeFirstResponder: &*self.view];
567→                return result;
568→            }
569→        }
570→        false
571→    }
572→}
573→
574→impl Drop for GhosttyOverlay {
575→    fn drop(&mut self) {
576→        // Remove from superview to clean up
577→        self.view.removeFromSuperview();
578→    }
579→}
