581→/// Get the raw NSWindow pointer from a Tauri webview window.
582→pub fn get_nswindow(window: &tauri::WebviewWindow) -> Result<*mut c_void, String> {
583→    #[cfg(target_os = "macos")]
584→    {
585→        use raw_window_handle::{HasWindowHandle, RawWindowHandle};
586→
587→        let handle = window
588→            .window_handle()
589→            .map_err(|e| format!("Failed to get window handle: {}", e))?;
590→
591→        match handle.as_raw() {
592→            RawWindowHandle::AppKit(handle) => {
593→                // ns_view is the content view — we need the window.
594→                // Get the window from the view.
595→                let ns_view = handle.ns_view.as_ptr() as *mut c_void;
596→                let ns_window: *mut c_void =
597→                    unsafe { msg_send![ns_view as *mut AnyObject, window] };
598→                Ok(ns_window)
599→            }
600→            _ => Err("Expected AppKit window handle on macOS".into()),
601→        }
602→    }
603→
604→    #[cfg(not(target_os = "macos"))]
605→    {
606→        let _ = window;
607→        Err("NSView overlay is only supported on macOS".into())
608→    }
609→}
