 41→#[tauri::command]
 42→fn list_repos() -> Result<Vec<git::RepoInfo>, String> {
 43→    let repo_paths = config::discover_repos();
 44→    let registered = config::get_registered_repos();
 45→    let registered_set: HashSet<String> = registered.into_iter().collect();
 46→    let mut repos = Vec::new();
 47→    for path in repo_paths {
 48→        match git::get_repo_info(&path) {
 49→            Ok(mut info) => {
 50→                info.registered = registered_set.contains(&path);
 51→                repos.push(info);
 52→            }
 53→            Err(e) => eprintln!("Skipping repo {}: {}", path, e),
 54→        }
 55→    }
 56→    Ok(repos)
 57→}
