185→/// Read a blob from the entire/checkpoints/v1 branch by path
186→fn read_blob(repo: &git2::Repository, path: &str) -> Result<String, String> {
187→    let branch_ref = repo
188→        .find_branch("entire/checkpoints/v1", git2::BranchType::Local)
189→        .map_err(|e| format!("No checkpoint branch: {}", e))?;
190→
191→    let commit = branch_ref
192→        .get()
193→        .peel_to_commit()
194→        .map_err(|e| format!("Failed to peel: {}", e))?;
195→
196→    let tree = commit
197→        .tree()
198→        .map_err(|e| format!("Failed to get tree: {}", e))?;
199→
200→    let entry = tree
201→        .get_path(std::path::Path::new(path))
202→        .map_err(|e| format!("Path not found: {}", e))?;
203→
204→    let blob = repo
205→        .find_blob(entry.id())
206→        .map_err(|e| format!("Failed to read blob: {}", e))?;
207→
208→    std::str::from_utf8(blob.content())
209→        .map(|s| s.to_string())
210→        .map_err(|e| format!("Invalid UTF-8: {}", e))
211→}
