252→#[tauri::command]
253→fn get_entire_logs(repo_path: String, tail_lines: u32) -> Result<EntireLogResult, String> {
254→    let log_path = std::path::Path::new(&repo_path).join(".entire/logs/entire.log");
255→    if !log_path.exists() {
256→        return Err("No log file found".to_string());
257→    }
258→
259→    let metadata = std::fs::metadata(&log_path)
260→        .map_err(|e| format!("Failed to read log metadata: {}", e))?;
261→    let file_size_bytes = metadata.len();
262→
263→    let file = std::fs::File::open(&log_path)
264→        .map_err(|e| format!("Failed to open log file: {}", e))?;
265→
266→    // Count total lines
267→    let reader = BufReader::new(&file);
268→    let all_lines: Vec<String> = reader.lines().filter_map(|l| l.ok()).collect();
269→    let total_lines = all_lines.len() as u32;
270→
271→    // Take last N lines
272→    let start = all_lines.len().saturating_sub(tail_lines as usize);
273→    let lines = all_lines[start..].to_vec();
274→
275→    Ok(EntireLogResult {
276→        lines,
277→        total_lines,
278→        file_size_bytes,
279→    })
280→}
