import { useState, useRef, useEffect, useCallback } from "react";
import { FindBar } from "./FindBar";

interface SearchableContainerProps {
  isSearchOpen: boolean;
  onClose: () => void;
  children: React.ReactNode;
  className?: string;
}

/**
 * Find all text matches within a container, returning Range objects.
 */
function findMatches(container: HTMLElement, query: string): Range[] {
  if (!query) return [];

  const lowerQuery = query.toLowerCase();
  const ranges: Range[] = [];
  const walker = document.createTreeWalker(
    container,
    NodeFilter.SHOW_TEXT,
    null
  );

  let node: Text | null;
  while ((node = walker.nextNode() as Text | null)) {
    const text = (node.textContent ?? "").toLowerCase();
    let idx = 0;
    while (idx < text.length) {
      const found = text.indexOf(lowerQuery, idx);
      if (found === -1) break;

      const range = document.createRange();
      range.setStart(node, found);
      range.setEnd(node, found + query.length);
      ranges.push(range);

      idx = found + lowerQuery.length;
    }
  }

  return ranges;
}

/**
 * Navigate to a match by selecting its Range and scrolling into view.
 */
function navigateToMatch(matches: Range[], index: number) {
  if (index < 0 || index >= matches.length) return;

  const sel = window.getSelection();
  if (!sel) return;

  sel.removeAllRanges();
  sel.addRange(matches[index]);

  const el = matches[index].startContainer.parentElement;
  el?.scrollIntoView({ block: "center", behavior: "smooth" });
}

export function SearchableContainer({
  isSearchOpen,
  onClose,
  children,
  className,
}: SearchableContainerProps) {
  const contentRef = useRef<HTMLDivElement>(null);
  const [query, setQuery] = useState("");
  const [matches, setMatches] = useState<Range[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const debounceRef = useRef<ReturnType<typeof setTimeout>>(undefined);

  // Find matches when query changes
  useEffect(() => {
    clearTimeout(debounceRef.current);

    if (!query || !contentRef.current) {
      setMatches([]);
      setCurrentIndex(0);
      return;
    }

    debounceRef.current = setTimeout(() => {
      if (!contentRef.current) return;
      const found = findMatches(contentRef.current, query);
      setMatches(found);
      if (found.length > 0) {
        setCurrentIndex(1);
        navigateToMatch(found, 0);
      } else {
        setCurrentIndex(0);
      }
    }, 150);

    return () => clearTimeout(debounceRef.current);
  }, [query]);

  const handleNext = useCallback(() => {
    if (matches.length === 0) return;
    const next = currentIndex >= matches.length ? 1 : currentIndex + 1;
    setCurrentIndex(next);
    navigateToMatch(matches, next - 1);
  }, [matches, currentIndex]);

  const handlePrevious = useCallback(() => {
    if (matches.length === 0) return;
    const prev = currentIndex <= 1 ? matches.length : currentIndex - 1;
    setCurrentIndex(prev);
    navigateToMatch(matches, prev - 1);
  }, [matches, currentIndex]);

  const handleClose = useCallback(() => {
    setQuery("");
    setMatches([]);
    setCurrentIndex(0);
    window.getSelection()?.removeAllRanges();
    onClose();
  }, [onClose]);

  // Reset on close
  useEffect(() => {
    if (!isSearchOpen) {
      setQuery("");
      setMatches([]);
      setCurrentIndex(0);
      window.getSelection()?.removeAllRanges();
    }
  }, [isSearchOpen]);

  return (
    <div className={`relative ${className ?? ""}`}>
      {isSearchOpen && (
        <div className="absolute right-0 top-0 z-20">
          <FindBar
            query={query}
            onQueryChange={setQuery}
            currentMatch={currentIndex}
            totalMatches={matches.length}
            onNext={handleNext}
            onPrevious={handlePrevious}
            onClose={handleClose}
          />
        </div>
      )}
      <div ref={contentRef} className="contents">
        {children}
      </div>
    </div>
  );
}

