import { useState, useRef, useEffect, useCallback } from "react";
import { FindBar } from "./FindBar";

interface SearchableContainerProps {
  isSearchOpen: boolean;
  onClose: () => void;
  children: React.ReactNode;
  className?: string;
}

/**
 * Find all text matches within a container, returning Range objects.
 */
function findMatches(container: HTMLElement, query: string): Range[] {
  if (!query) return [];

  const lowerQuery = query.toLowerCase();
  const ranges: Range[] = [];
  const walker = document.createTreeWalker(
    container,
    NodeFilter.SHOW_TEXT,
    null
  );

  let node: Text | null;
  while ((node = walker.nextNode() as Text | null)) {
    const text = (node.textContent ?? "").toLowerCase();
    let idx = 0;
    while (idx < text.length) {
      const found = text.indexOf(lowerQuery, idx);
      if (found === -1) break;

      const range = document.createRange();
      range.setStart(node, found);
      range.setEnd(node, found + query.length);
      ranges.push(range);

      idx = found + lowerQuery.length;
    }
  }

  return ranges;
}

/**
 * Navigate to a match by selecting its Range and scrolling into view.
 */
function navigateToMatch(matches: Range[], index: number) {
  if (index < 0 || index >= matches.length) return;
  const activeEl = document.activeElement as HTMLElement | null;

  const sel = window.getSelection();
  if (!sel) return;

  sel.removeAllRanges();
  sel.addRange(matches[index]);

  const el = matches[index].startContainer.parentElement;
  el?.scrollIntoView({ block: "center", behavior: "smooth" });

  // Restore focus so the search input doesn't lose it
  activeEl?.focus();
}

